      const b = valB.priority ?? Number.POSITIVE_INFINITY;
      if (a !== b) return a - b;
      const labelA = valA.label ?? keyA;
      const labelB = valB.label ?? keyB;
      return labelA.localeCompare(labelB, ["en"]);
    }
  );

  const reordered = {};
  for (const [key, child] of sortedChildren) {
    sortCategoryTree(child);
    reordered[key] = child;
