// Canvas utility functions

/**
 * Get 2D context with image smoothing disabled for crisp pixel rendering
 * @param {HTMLCanvasElement} canvas - Canvas element
 * @param {boolean} willReadFrequently - Whether the context will be used for frequent getImageData calls
 * @returns {CanvasRenderingContext2D} Context with smoothing disabled
 */
export function get2DContext(canvas, willReadFrequently = false) {
	const ctx = canvas.getContext('2d', { willReadFrequently });
	ctx.imageSmoothingEnabled = false;
	return ctx;
}

/**
 * Get zPos for a layer
 */
export function getZPos(itemId, layerNum = 1) {
  const meta = window.itemMetadata[itemId];
  if (!meta) return 100;

  const layerKey = `layer_${layerNum}`;
  const layer = meta.layers?.[layerKey];

  return layer?.zPos ?? 100;
}

/**
 * Draw a checkered transparency background (like image editors)
 * @param {CanvasRenderingContext2D} context - Canvas context
 * @param {number} width - Canvas width
 * @param {number} height - Canvas height
 * @param {number} squareSize - Size of each checker square (default 8px)
 */
export function drawTransparencyBackground(
  context,
  width,
  height,
  squareSize = 8
) {
  const lightGray = "#CCCCCC";
  const darkGray = "#999999";

  for (let y = 0; y < height; y += squareSize) {
    for (let x = 0; x < width; x += squareSize) {
      // Alternate colors in a checkerboard pattern
      const isEvenRow = Math.floor(y / squareSize) % 2 === 0;
      const isEvenCol = Math.floor(x / squareSize) % 2 === 0;
      const isLight = isEvenRow === isEvenCol;

      context.fillStyle = isLight ? lightGray : darkGray;
      context.fillRect(x, y, squareSize, squareSize);
    }
  }
}

import { getCanvas } from "./renderer.js";

/**
 * Get canvas as blob for ZIP export
 */
export function getCanvasBlob() {
  const canvas = getCanvas();
  if (!canvas) {
    console.error("Canvas not initialized");
    return Promise.reject(new Error("Canvas not initialized"));
  }

  return new Promise((resolve) => {
    canvas.toBlob((blob) => resolve(blob), "image/png");
  });
}

/**
 * Download canvas as PNG (exports the offscreen canvas directly)
 */
// allow injection of getCanvasBlob for testing
export async function downloadAsPNG(filename = "character-spritesheet.png", getCanvasBlobFunc) {
  try {
    const blob = await (getCanvasBlobFunc ?? getCanvasBlob)();
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = filename;
    a.click();
    URL.revokeObjectURL(url);
  } catch (error) {
    console.error("Error downloading PNG:", error);
  }
}

export function downloadFile(content, filename, type = "text/plain") {
  const blob = new Blob([content], { type });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  a.click();
  URL.revokeObjectURL(url);
}

import { FRAME_SIZE } from "../state/constants.js";
import { animationRowsLayout } from "../custom-animations.js";

/**
 * Draw a single frame from source to destination
 * If source is smaller than destination, center it without scaling
 * @param {CanvasRenderingContext2D} destCtx - Destination context
 * @param {{x: number, y: number}} destPos - Destination position
 * @param {number} destFrameSize - Destination frame size
 * @param {CanvasImageSource} src - Source image
 * @param {{x: number, y: number}} srcPos - Source position
 * @param {number} srcFrameSize - Source frame size
 */
export function drawFrameToFrame(
  destCtx,
  destPos,
  destFrameSize,
  src,
  srcPos,
  srcFrameSize
) {
  if (srcFrameSize === destFrameSize) {
    // Same size - direct copy
    destCtx.drawImage(
      src,
      srcPos.x,
      srcPos.y,
      srcFrameSize,
      srcFrameSize,
      destPos.x,
      destPos.y,
      destFrameSize,
      destFrameSize
    );
  } else {
    // Different sizes - center the source frame in the destination without scaling
    // For example: 64x64 source centered in 128x128 dest = offset by 32px
    const offset = (destFrameSize - srcFrameSize) / 2;
    destCtx.drawImage(
      src,
      srcPos.x,
      srcPos.y,
      srcFrameSize,
      srcFrameSize, // source rect (64x64)
      destPos.x + offset,
      destPos.y + offset,
      srcFrameSize,
      srcFrameSize // dest rect (centered, not scaled)
    );
  }
}

/**
 * Extract frames from a standard sprite sheet and redraw them into a custom animation layout
 * @param {CanvasRenderingContext2D} customAnimationContext - Destination context
 * @param {object} customAnimationDefinition - Custom animation definition from custom-animations.js
 * @param {number} offsetY - Y offset to draw at
 * @param {CanvasImageSource} src - Source sprite sheet image
 */
export function drawFramesToCustomAnimation(
  customAnimationContext,
  customAnimationDefinition,
  offsetY,
  src
) {
  const frameSize = customAnimationDefinition.frameSize;

  // Check if this is a single-animation sprite (e.g., sit.png) or full universal sheet
  // Single animation sprites are typically 192px or 832px wide and 256px tall
  const isSingleAnimation = src.height <= 256;

  for (let i = 0; i < customAnimationDefinition.frames.length; ++i) {
    const frames = customAnimationDefinition.frames[i];
    for (let j = 0; j < frames.length; ++j) {
      const frameSpec = frames[j]; // e.g., "sit-n,2"
      const [srcRowName, srcColumnStr] = frameSpec.split(",");
      const srcColumn = parseInt(srcColumnStr);

      let srcRow;
      if (isSingleAnimation) {
        // For single animation sprites, rows are 0-3 (n, w, s, e)
        // Extract direction from srcRowName (e.g., "sit-n" -> "n")
        const direction = srcRowName.split("-")[1];
        const directionMap = { n: 0, w: 1, s: 2, e: 3 };
        srcRow = directionMap[direction] || 0;
      } else {
        // For universal sheet, use animationRowsLayout
        srcRow = animationRowsLayout ? animationRowsLayout[srcRowName] : i;
      }

      const srcX = FRAME_SIZE * srcColumn;
      const srcY = FRAME_SIZE * srcRow;
      const destX = frameSize * j;
      const destY = frameSize * i + offsetY;

      drawFrameToFrame(
        customAnimationContext,
        { x: destX, y: destY }, // dest position
        frameSize, // dest frame size
        src,
        { x: srcX, y: srcY }, // source position
        FRAME_SIZE // source frame size (64px)
      );
    }
  }
}

let loadedImages = {};
let imagesToLoad = 0;
let imagesLoaded = 0;

/**
 * Load an image
 */
export function loadImage(src) {
  return new Promise((resolve, reject) => {
    if (loadedImages[src]) {
      resolve(loadedImages[src]);
      return;
    }

    // Mark start of image load for profiling
    const profiler = window.profiler;
    if (profiler) {
      profiler.mark(`image-load:${src}:start`);
    }

    const img = new Image();
    img.onload = () => {
      loadedImages[src] = img;
      imagesLoaded++;

      // Mark end and measure
      if (profiler) {
        profiler.mark(`image-load:${src}:end`);
        profiler.measure(`image-load:${src}`, `image-load:${src}:start`, `image-load:${src}:end`);
      }

      resolve(img);
    };
    img.onerror = () => {
      console.error(`Failed to load image: ${src}`);
      imagesLoaded++;
      reject(new Error(`Failed to load ${src}`));
    };
    img.src = src;
    imagesToLoad++;
  });
}

/**
 * Load multiple images in parallel
 * @param {Array} items - Array of items with a spritePath property
 * @param {Function} getPath - Optional function to extract path from item (defaults to item.spritePath)
 * @returns {Promise<Array>} Array of {item, img, success} objects
 */
export async function loadImagesInParallel(items, getPath = (item) => item.spritePath) {
  const promises = items.map(item =>
    loadImage(getPath(item))
      .then(img => ({ item, img, success: true }))
      .catch(err => {
        if (window.DEBUG) {
          console.warn(`Failed to load sprite: ${getPath(item)}`);
        }
        return { item, img: null, success: false };
      })
  );

  return Promise.all(promises);
}

export function applyTransparencyMaskToCanvas(canvas, ctx) {
  if (!canvas) {
    console.error("Canvas not initialized");
    return;
  }
  const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height),
    pix = imgData.data,
    n = pix.length;

  for (let i = 0; i < n; i += 4) {
    const a = pix[i + 3];
    if (a > 0) {
      const r = pix[i];
      const g = pix[i + 1];
      const b = pix[i + 2];
      if (r === 255 && g === 44 && b === 230) {
        pix[i + 3] = 0;
      }
    }
  }
  ctx.putImageData(imgData, 0, 0);
}

import { previewCanvas, previewCtx } from "./preview-canvas.js";
import { state } from "../state/state.js";
import { FRAME_SIZE, ANIMATION_CONFIGS } from "../state/constants.js";
import { get2DContext, drawTransparencyBackground } from "./canvas-utils.js";
import { applyTransparencyMaskToCanvas } from "./mask.js";
import { canvas } from "./renderer.js";
import { customAnimations } from "../custom-animations.js";

// Animation preview state
let animationFrames = [1, 2, 3, 4, 5, 6, 7, 8]; // default for walk
let animRowStart = 8; // default for walk (row number)
let animRowNum = 4; // default for walk (number of rows to stack)
let currentFrameIndex = 0;
let lastFrameTime = Date.now();
let animationFrameId = null;

// Track custom animations present in current render
let currentCustomAnimations = {};
let customAnimYPositions = {}; // Y positions of custom animations in canvas
let activeCustomAnimation = null; // Currently selected custom animation for preview

export { activeCustomAnimation };

/**
 * Set which animation to preview
 */
export function setPreviewAnimation(animationName) {
	// Check if this is a custom animation
	if (customAnimations && customAnimations[animationName]) {
		const customAnimDef = customAnimations[animationName];
		activeCustomAnimation = animationName;

		// Extract frame cycle from custom animation definition
		// Custom animations have 4 rows (n, w, s, e), we'll show all columns from first row
		const frameCount = customAnimDef.frames[0].length;

		// Check if we should skip the first frame (frame 0)
		const skipFirstFrame = customAnimDef.skipFirstFrameInPreview || false;
		animationFrames = skipFirstFrame
			? Array.from({ length: frameCount - 1 }, (_, i) => i + 1) // [1, 2, 3, ..., 8]
			: Array.from({ length: frameCount }, (_, i) => i); // [0, 1, 2, ..., 8]

		animRowStart = 0; // Not used for custom animations
		animRowNum = 4; // Show all 4 directions
		currentFrameIndex = 0;

		return animationFrames;
	}

	// Standard animation
	activeCustomAnimation = null;
	const config = ANIMATION_CONFIGS[animationName];
	if (!config) {
		console.error("Unknown animation:", animationName);
		return [];
	}

	animationFrames = config.cycle;
	animRowStart = config.row;
	animRowNum = config.num;
	currentFrameIndex = 0;

	return animationFrames; // Return for display
}

/**
 * Start the preview animation loop
 */
export function startPreviewAnimation() {
	if (animationFrameId !== null) {
		return; // Already running
	}

	function nextFrame() {
		const fpsInterval = 1000 / 8; // 8 FPS
		const now = Date.now();
		const elapsed = now - lastFrameTime;

		if (elapsed > fpsInterval) {
			lastFrameTime = now - (elapsed % fpsInterval);

			if (previewCtx && canvas) {
				previewCtx.clearRect(
					0,
					0,
					previewCanvas.width,
					previewCanvas.height
				);

				// Draw transparency grid if enabled
				if (state.showTransparencyGrid) {
					drawTransparencyBackground(
						previewCtx,
						previewCanvas.width,
						previewCanvas.height
					);
				}

				currentFrameIndex =
					(currentFrameIndex + 1) % animationFrames.length;
				const currentFrame = animationFrames[currentFrameIndex];

				// Determine frameSize and Y offset based on animation type
				let frameSize = FRAME_SIZE;
				let yOffset = 0;

				if (activeCustomAnimation && customAnimations) {
					const customAnimDef = customAnimations[activeCustomAnimation];
					if (customAnimDef) {
						frameSize = customAnimDef.frameSize;
						yOffset =
							customAnimYPositions[activeCustomAnimation] || 0;
					}
				}

				let tmpCanvas;
				if (state.applyTransparencyMask) {
					// using a tmpCanvas here to avoid modifying the original offscreen canvas
					// which causes a bug if the user toggles the checkbox multiple times
					tmpCanvas = document.createElement("canvas");
					tmpCanvas.width = canvas.width;
					tmpCanvas.height = canvas.height;
					const tmpCtx = get2DContext(tmpCanvas);
					tmpCtx.drawImage(canvas, 0, 0);
					applyTransparencyMaskToCanvas(tmpCanvas, tmpCtx);
				} else {
					tmpCanvas = canvas;
				}

				// Draw stacked rows from main canvas to preview
				for (let i = 0; i < animRowNum; i++) {
					const srcY = activeCustomAnimation
						? yOffset + i * frameSize // Custom animation: use Y offset + row * frameSize
						: (animRowStart + i) * FRAME_SIZE; // Standard animation: use row * 64
					previewCtx.drawImage(
						tmpCanvas,
						currentFrame * frameSize, // source x
						srcY, // source y
						frameSize, // source width
						frameSize, // source height
						i * frameSize, // dest x (spread horizontally)
						0, // dest y
						frameSize, // dest width
						frameSize // dest height
					);
				}
			}
		}

		animationFrameId = requestAnimationFrame(nextFrame);
	}

	nextFrame();
}

/**
 * Stop the preview animation loop
 */
export function stopPreviewAnimation() {
	if (animationFrameId !== null) {
		cancelAnimationFrame(animationFrameId);
		animationFrameId = null;
	}
}

/**
 * Get list of custom animations present in current render
 * @returns {string[]} Array of custom animation names
 */
export function getCustomAnimations() {
	return currentCustomAnimations;
}

/**
 * Set the list of custom animations present in current render
 * @param {Record<string, Object>} customAnimations Record of
 * custom animation names mapped to their definitions
 */
export function setCurrentCustomAnimations(customAnimations) {
	currentCustomAnimations = customAnimations;
}

/**
 * Set the Y positions for custom animations
 * @param {Record<string, number>} yPositions Record of
 * custom animation names mapped to their Y positions
 */
export function setCustomAnimYPositions(yPositions) {
	customAnimYPositions = yPositions;
}

import { canvas } from "./renderer.js";
import { drawTransparencyBackground, get2DContext } from "./canvas-utils.js";
import { FRAME_SIZE } from "../state/constants.js";
import { applyTransparencyMaskToCanvas } from "./mask.js";
import { activeCustomAnimation, getCustomAnimations } from "./preview-animation.js";

let previewCanvas = null;
let previewCtx = null;

export { previewCanvas, previewCtx };

/**
 * Copy offscreen canvas to a preview canvas with optional transparency grid
 * @param {HTMLCanvasElement} previewCanvasElement - The preview canvas to copy to
 * @param {boolean} showTransparencyGrid - Whether to draw transparency grid background
 * @param {boolean} applyTransparencyMask - Whether to apply transparency mask
 * @param {number} zoomLevel - Zoom level to apply (optional, will use CSS zoom)
 */
export function copyToPreviewCanvas(
	previewCanvasElement,
	showTransparencyGrid = false,
	applyTransparencyMask = false,
	zoomLevel = 1
) {
	if (!canvas || !previewCanvasElement) {
		console.error("Canvas not initialized");
		return;
	}

	const previewCtx = get2DContext(previewCanvasElement);

	// Match preview canvas size to offscreen canvas
	previewCanvasElement.width = canvas.width;
	previewCanvasElement.height = canvas.height;

	// Clear preview canvas
	previewCtx.clearRect(
		0,
		0,
		previewCanvasElement.width,
		previewCanvasElement.height
	);

	// Optionally draw transparency grid
	if (showTransparencyGrid) {
		drawTransparencyBackground(
			previewCtx,
			previewCanvasElement.width,
			previewCanvasElement.height
		);
	}

	// Copy from offscreen canvas to preview canvas
	if (applyTransparencyMask) {
		// using a tmpCanvas here to avoid modifying the original offscreen canvas
		// which causes a bug if the user toggles the checkbox multiple times
		const tmpCanvas = document.createElement("canvas");
		tmpCanvas.width = canvas.width;
		tmpCanvas.height = canvas.height;
		const tmpCtx = get2DContext(tmpCanvas);
		tmpCtx.drawImage(canvas, 0, 0);
		applyTransparencyMaskToCanvas(tmpCanvas, tmpCtx);
		previewCtx.drawImage(tmpCanvas, 0, 0);
	} else {
		// Direct copy
		previewCtx.drawImage(canvas, 0, 0);
	}

	// Apply zoom via CSS
	if (zoomLevel !== 1) {
		previewCanvasElement.style.zoom = zoomLevel.toString();
	}
}

/**
 * Initialize the preview canvas
 */
export function initPreviewCanvas(previewCanvasElement) {
	previewCanvas = previewCanvasElement;
	previewCtx = get2DContext(previewCanvas);
	const customAnimations = getCustomAnimations();

	// Size based on active animation
	let frameSize = FRAME_SIZE;
	if (activeCustomAnimation && customAnimations) {
		const customAnimDef = customAnimations[activeCustomAnimation];
		if (customAnimDef) {
			frameSize = customAnimDef.frameSize;
		}
	}

	previewCanvas.width = 4 * frameSize; // 4 directions
	previewCanvas.height = frameSize; // 1 frame tall
}

/**
 * Set preview canvas zoom level
 * @param {number} zoomLevel - Zoom level (0.5 to 2)
 */
export function setPreviewCanvasZoom(zoomLevel) {
	if (previewCanvas) {
		previewCanvas.style.zoom = zoomLevel.toString();
	}
}

// Canvas rendering module for Mithril UI
// Simplified renderer that draws character sprites based on selections

import { loadImage, loadImagesInParallel } from "./load-image.js";
import { getSpritePath } from "../state/path.js";
import { get2DContext, getZPos } from "./canvas-utils.js";
import { variantToFilename } from "../utils/helpers.js";
import { drawFramesToCustomAnimation } from "./draw-frames.js";
import {
  FRAME_SIZE,
  ANIMATION_OFFSETS,
  ANIMATION_CONFIGS,
} from "../state/constants.js";
import { customAnimations, customAnimationBase } from "../custom-animations.js";
import {
  setCurrentCustomAnimations,
  setCustomAnimYPositions,
} from "./preview-animation.js";
import { getSortedLayersByAnim } from "../state/meta.js";

export const SHEET_HEIGHT = 3456; // Full universal sheet height
export const SHEET_WIDTH = 832; // 13 frames * 64px

let canvas = null;
let ctx = null;
let layers = [];
let itemsToDraw = [];
let addedCustomAnimations = new Set();
let customAreaItems = {};

/**
 * Initialize the canvas (creates offscreen canvas)
 */
export function initCanvas() {
  canvas = document.createElement("canvas");
  ctx = get2DContext(canvas);
  canvas.width = SHEET_WIDTH;
  canvas.height = SHEET_HEIGHT;
}

export {
  canvas,
  ctx,
  layers,
  addedCustomAnimations,
  itemsToDraw,
  customAreaItems,
};

/**
 * Render character based on selections
 * @param {Object} selections - Selected items
 * @param {string} bodyType - Body type
 * @param {HTMLCanvasElement} targetCanvas - Canvas to render to (defaults to main canvas)
 */
export async function renderCharacter(
  selections,
  bodyType,
  targetCanvas = null
) {
  // Mark start for profiling
  const profiler = window.profiler;
  if (profiler) {
    profiler.mark("renderCharacter:start");
  }

  // Build list of items to draw
  itemsToDraw = [];
  const customAnimationItems = []; // Track items with custom animations
  addedCustomAnimations = new Set(); // Track which custom animations we've added

  // Import state to access custom uploaded image
  const appState = await import("../state/state.js").then(m => m.state);
  appState.renderCharacter.isRendering = true;
  m.redraw();

  try {
    // Use provided canvas or default to main canvas
    const renderCanvas = targetCanvas || canvas;
    const renderCtx = renderCanvas.getContext('2d', { willReadFrequently: true });

    if (!renderCanvas || !renderCtx) {
      console.error("Canvas not initialized");
      throw new Error("Canvas not initialized");
    }

    for (const [categoryPath, selection] of Object.entries(selections)) {
      const { itemId, variant } = selection;
      const meta = window.itemMetadata[itemId];

      if (!meta) continue;

      // Check if this body type is supported
      if (!meta.required.includes(bodyType)) {
        continue;
      }

      // Process all layers for this item
      for (let layerNum = 1; layerNum < 10; layerNum++) {
        // Check if this layer exists
        const layerKey = `layer_${layerNum}`;
        const layer = meta.layers?.[layerKey];
        if (!layer) break;

        const zPos = getZPos(itemId, layerNum);

        // Check if this layer has a custom animation
        if (layer.custom_animation) {
          const customAnimName = layer.custom_animation;
          addedCustomAnimations.add(customAnimName);

          // Get base path for this body type
          let basePath = layer[bodyType];
          if (!basePath) {
            continue;
          }

          // Custom animations use direct file path
          const spritePath = `spritesheets/${basePath}${variantToFilename(
            variant
          )}.png`;

          customAnimationItems.push({
            itemId,
            variant,
            spritePath,
            zPos,
            layerNum,
            customAnimation: customAnimName,
            isCustom: true,
          });

          continue; // Skip standard animation processing for this layer
        }

        // Process standard animations for this layer
        for (const [animName, yPos] of Object.entries(ANIMATION_OFFSETS)) {
          // Skip if item doesn't have animations array (custom animations only)
          if (!meta.animations || meta.animations.length === 0) {
            continue;
          }

          // Map folder name to metadata name for checking support
          // e.g., "combat_idle" -> check for "combat" or "1h_slash" in metadata
          let metadataAnimName = animName;
          if (animName === "combat_idle") {
            // combat_idle is supported if item has "combat" in metadata
            if (!meta.animations.includes("combat")) continue;
          } else if (animName === "backslash") {
            // backslash is supported if item has "1h_slash" OR "1h_backslash" in metadata
            if (
              !meta.animations.includes("1h_slash") &&
              !meta.animations.includes("1h_backslash")
            )
              continue;
          } else if (animName === "halfslash") {
            // halfslash is supported if item has "1h_halfslash" in metadata
            if (!meta.animations.includes("1h_halfslash")) continue;
          } else {
            // For all other animations, direct match required
            if (!meta.animations.includes(animName)) continue;
          }

          const spritePath = getSpritePath(
            itemId,
            variant,
            bodyType,
            animName,
            layerNum,
            selections,
            meta
          );

          itemsToDraw.push({
            itemId,
            variant,
            spritePath,
            zPos,
            layerNum,
            animation: animName,
            yPos,
            isCustom: false,
          });
        }
      }
    }

    // Add custom uploaded image to itemsToDraw if present
    if (appState.customUploadedImage) {
      // Add custom image to be drawn at all standard animation positions
      for (const [animName, yPos] of Object.entries(ANIMATION_OFFSETS)) {
        itemsToDraw.push({
          itemId: "custom-upload",
          variant: null,
          spritePath: null, // Will draw directly from Image object
          zPos: appState.customImageZPos,
          layerNum: 0,
          animation: animName,
          yPos,
          isCustom: false,
          customImage: appState.customUploadedImage, // Store the Image object
        });
      }
    }

    // Sort standard items by zPos only (lower zPos = drawn first = behind)
    // This ensures shadow (zPos=0) is drawn before body (zPos=10), etc.
    itemsToDraw.sort((a, b) => a.zPos - b.zPos);

    // save layers for external access
    layers = itemsToDraw
      .map((item) => {
        const layer = Object.assign({}, item);
        layer.fileName = item.spritePath.substring("spritesheets/".length);
        delete layer.spritePath;
        return layer;
      })
      .reduce((acc, layer) => {
        const animation = layer.animation;
        const accLayer = acc.find(
          (l) => l.itemId === layer.itemId && l.layerNum === layer.layerNum
        );
        if (!accLayer) {
          layer.supportedAnimations = [animation];
          delete layer.animation;
          acc.push(layer);
        } else {
          accLayer.supportedAnimations.push(animation);
        }
        return acc;
      }, []);

    // Calculate total canvas height needed (standard sheet + custom animations)
    let totalHeight = SHEET_HEIGHT;
    let totalWidth = SHEET_WIDTH;
    let currentCustomAnimations = {};

    if (addedCustomAnimations.size > 0 && customAnimations) {
      for (const customAnimName of addedCustomAnimations) {
        const customAnimDef = customAnimations[customAnimName];
        if (customAnimDef) {
          const animHeight =
            customAnimDef.frameSize * customAnimDef.frames.length;
          const animWidth =
            customAnimDef.frameSize * customAnimDef.frames[0].length;
          totalHeight += animHeight;
          totalWidth = Math.max(totalWidth, animWidth);
        }
        currentCustomAnimations[customAnimName] = customAnimDef;
      }
    }

    // Resize canvas to fit all content
    renderCanvas.width = totalWidth;
    renderCanvas.height = totalHeight;

    // Clear canvas (no transparency background on offscreen canvas)
    renderCtx.clearRect(0, 0, renderCanvas.width, renderCanvas.height);

    // Store custom animations for animation preview dropdown
    setCurrentCustomAnimations(currentCustomAnimations);

    // Calculate custom animation Y positions first (needed for drawing standard items into custom areas)
    const customAnimYPositions = {};
    if (addedCustomAnimations.size > 0 && customAnimations) {
      let currentY = SHEET_HEIGHT;
      for (const customAnimName of addedCustomAnimations) {
        customAnimYPositions[customAnimName] = currentY;
        const customAnimDef = customAnimations[customAnimName];
        if (customAnimDef) {
          const animHeight =
            customAnimDef.frameSize * customAnimDef.frames.length;
          currentY += animHeight;
        }
      }
    }

    // Store Y positions for external access
    setCustomAnimYPositions(customAnimYPositions);

    // Load all standard animation images in parallel and attach them to their items
    const loadPromises = itemsToDraw.map((item) => {
      if (item.customImage) {
        // Custom image already loaded
        return Promise.resolve({ item, img: item.customImage, success: true });
      } else {
        // Load standard image
        return loadImage(item.spritePath)
          .then((img) => ({ item, img, success: true }))
          .catch((err) => {
            if (window.DEBUG) {
              console.warn(`Failed to load sprite: ${item.spritePath}`);
            }
            return { item, img: null, success: false };
          });
      }
    });

    const loadedItems = await Promise.all(loadPromises);

    // Draw all items in sorted z-order
    for (const { item, img, success } of loadedItems) {
      if (success && img) {
        renderCtx.drawImage(img, 0, item.yPos);
      }
    }

    // Now handle custom animations (wheelchair, etc.)
    if (addedCustomAnimations.size > 0 && customAnimations) {
      // For each custom animation area, we need to draw layers in zPos order
      for (const customAnimName of addedCustomAnimations) {
        const customAnimDef = customAnimations[customAnimName];
        if (!customAnimDef) continue;

        const offsetY = customAnimYPositions[customAnimName];
        const baseAnim = customAnimationBase
          ? customAnimationBase(customAnimDef)
          : null;

        // Collect all items that need to be drawn in this custom animation area
        customAreaItems[customAnimName] = [];

        // 1. Add custom animation sprite layers (wheelchair background/foreground)
        for (const item of customAnimationItems) {
          if (item.customAnimation === customAnimName) {
            customAreaItems[customAnimName].push({
              type: "custom_sprite",
              zPos: item.zPos,
              spritePath: item.spritePath,
              itemId: item.itemId,
              animation: customAnimName,
            });
          }
        }

        // 2. Add standard items that need to be extracted into this custom animation
        // (e.g., body "sit" frames go into wheelchair custom animation)
        if (baseAnim) {
          for (const item of itemsToDraw) {
            if (item.animation === baseAnim) {
              customAreaItems[customAnimName].push({
                type: "extracted_frames",
                zPos: item.zPos,
                spritePath: item.spritePath,
                itemId: item.itemId,
                animation: item.animation,
              });
            }
          }
        }

        // Sort by zPos to get correct layer order
        customAreaItems[customAnimName].sort((a, b) => a.zPos - b.zPos);

        // Load all custom area images in parallel
        const loadedCustomImages = await loadImagesInParallel(
          customAreaItems[customAnimName]
        );

        // Draw in zPos order
        for (const { item: areaItem, img, success } of loadedCustomImages) {
          if (success && img) {
            if (areaItem.type === "custom_sprite") {
              // Draw custom sprite directly (wheelchair background or foreground)
              renderCtx.drawImage(img, 0, offsetY);
            } else if (areaItem.type === "extracted_frames") {
              // Extract and draw frames from standard sprite
              drawFramesToCustomAnimation(
                renderCtx,
                customAnimDef,
                offsetY,
                img
              );
            }
          }
        }
      }
    }
  } finally {
    appState.renderCharacter.isRendering = false;
    m.redraw();

    // Mark end and measure
    if (profiler) {
      profiler.mark("renderCharacter:end");
      profiler.measure(
        "renderCharacter",
        "renderCharacter:start",
        "renderCharacter:end"
      );
    }
  }
}

/**
 * Extract a specific animation from the main canvas
 * Returns a new canvas with just that animation
 */
export function extractAnimationFromCanvas(animationName) {
  if (!canvas) {
    return null;
  }

  const config = ANIMATION_CONFIGS[animationName];
  if (!config) {
    console.error("Unknown animation:", animationName);
    return null;
  }

  const { row, num } = config;
  const srcY = row * FRAME_SIZE;
  const srcHeight = num * FRAME_SIZE;

  // Create new canvas for this animation
  const animCanvas = document.createElement("canvas");
  animCanvas.width = SHEET_WIDTH;
  animCanvas.height = srcHeight;
  const animCtx = get2DContext(animCanvas);

  // Copy animation from main canvas
  animCtx.drawImage(
    canvas,
    0,
    srcY,
    SHEET_WIDTH,
    srcHeight,
    0,
    0,
    SHEET_WIDTH,
    srcHeight
  );

  return animCanvas;
}

/**
 * Get current canvas reference (for external use)
 */
export function getCanvas() {
  return canvas;
}

/**
 * Render a single item to a new canvas
 * Returns a canvas with just this one item rendered
 */
export async function renderSingleItem(
  itemId,
  variant,
  bodyType,
  selections,
  singleLayer = null
) {
  const meta = window.itemMetadata[itemId];
  if (!meta) {
    console.error("Item metadata not found:", itemId);
    return null;
  }

  // Check if this body type is supported
  if (!meta.required.includes(bodyType)) {
    console.error("Body type not supported for this item:", bodyType, itemId);
    return null;
  }

  // Check if this is a custom animation item
  const layer1 =
    meta.layers && Object.values(meta.layers).find((l) => l.custom_animation);
  const hasCustomAnimation = layer1 && layer1.custom_animation;

  let itemCanvas, itemCtx;

  if (hasCustomAnimation && customAnimations) {
    // Custom animation item - use custom animation size
    const customAnimName = layer1.custom_animation;
    const customAnimDef = customAnimations[customAnimName];
    if (!customAnimDef) {
      console.error("Custom animation definition not found:", customAnimName);
      return null;
    }

    const animHeight = customAnimDef.frameSize * customAnimDef.frames.length;
    const animWidth = customAnimDef.frameSize * customAnimDef.frames[0].length;

    const customLayers = Object.values(meta.layers).filter(
      (l) => l.custom_animation
    );
    const customAnimationsInItem = customLayers
      .map((l) => l.custom_animation)
      .filter((value, index, array) => array.indexOf(value) === index);
    const numCustomAnims = customAnimationsInItem.length;
    const getYPosForCustomAnim = (name) => {
      const index = customAnimationsInItem.indexOf(name);
      return SHEET_HEIGHT + index * animHeight;
    };

    itemCanvas = document.createElement("canvas");
    itemCanvas.width = animWidth;
    itemCanvas.height = SHEET_HEIGHT + animHeight * numCustomAnims;
    itemCtx = get2DContext(itemCanvas);

    // Render all layers of this custom animation item
    const customSprites = [];
    const animsList = getSortedLayersByAnim(itemId, true);
    for (const animName in animsList) {
      for (let layerNum = 1; layerNum < 10; layerNum++) {
        if (singleLayer !== null && layerNum !== singleLayer) continue;
        const animLayer = animsList[animName].find(
          (l) => l.animLayerNum === layerNum
        );
        const layerKey = `layer_${animLayer.layerNum}`;
        const layer = meta.layers?.[layerKey];
        if (!layer) break;

        const yPos = getYPosForCustomAnim(layer.custom_animation);
        let basePath = layer[bodyType];
        if (!basePath) continue;

        const spritePath = `spritesheets/${basePath}${variantToFilename(
          variant
        )}.png`;
        customSprites.push({ spritePath, zPos: animLayer.zPos, yPos });
      }
    }

    // Sort by zPos
    customSprites.sort((a, b) => a.zPos - b.zPos);

    // Load all layers in parallel
    const loadedSprites = await loadImagesInParallel(customSprites);

    // Draw layers in order
    for (const { item: sprite, img, success } of loadedSprites) {
      if (success && img) {
        itemCtx.drawImage(img, 0, sprite.yPos);
      }
    }
  } else {
    // Standard animation item - use standard sheet size
    itemCanvas = document.createElement("canvas");
    itemCanvas.width = SHEET_WIDTH;
    itemCanvas.height = SHEET_HEIGHT;
    itemCtx = get2DContext(itemCanvas);
  }

  // Build list of sprites to draw for this item
  const spritesToDraw = [];

  for (let layerNum = 1; layerNum < 10; layerNum++) {
    if (singleLayer !== null && layerNum !== singleLayer) continue;
    const layerKey = `layer_${layerNum}`;
    if (!meta.layers?.[layerKey]) break;

    const zPos = getZPos(itemId, layerNum);

    // Add each animation for this layer
    for (const [animName, yPos] of Object.entries(ANIMATION_OFFSETS)) {
      // Check animation support (same logic as renderCharacter)
      let metadataAnimName = animName;
      if (animName === "combat_idle") {
        if (!meta.animations.includes("combat")) continue;
      } else if (animName === "backslash") {
        if (
          !meta.animations.includes("1h_slash") &&
          !meta.animations.includes("1h_backslash")
        )
          continue;
      } else if (animName === "halfslash") {
        if (!meta.animations.includes("1h_halfslash")) continue;
      } else {
        if (!meta.animations.includes(animName)) continue;
      }

      const spritePath = getSpritePath(
        itemId,
        variant,
        bodyType,
        animName,
        layerNum,
        selections,
        meta
      );

      spritesToDraw.push({
        itemId,
        variant,
        spritePath,
        zPos,
        layerNum,
        animation: animName,
        yPos,
      });
    }

    // Sort by animation first, then by zPos
    spritesToDraw.sort((a, b) => {
      if (a.yPos !== b.yPos) return a.yPos - b.yPos;
      return a.zPos - b.zPos;
    });

    // Load all images in parallel
    const loadedImages = await loadImagesInParallel(spritesToDraw);

    // Draw images in order
    for (const { item: sprite, img, success } of loadedImages) {
      if (success && img) {
        itemCtx.drawImage(img, 0, sprite.yPos);
      }
    }
  }

  return itemCanvas;
}

/**
 * Render a single item for a single animation to a new canvas
 * Returns a canvas with just this one item's one animation rendered
 */
export async function renderSingleItemAnimation(
  itemId,
  variant,
  bodyType,
  animationName,
  selections,
  singleLayer = null
) {
  const meta = window.itemMetadata[itemId];
  if (!meta) {
    console.error("Item metadata not found:", itemId);
    return null;
  }

  // Check if this body type is supported
  if (!meta.required.includes(bodyType)) {
    return null;
  }

  // Check if this is a custom animation item
  const layer1 = meta.layers?.layer_1;
  const hasCustomAnimation = layer1 && layer1.custom_animation;

  if (hasCustomAnimation && customAnimations) {
    // Custom animation item - just return the full item canvas (custom animations are not split by standard animation)
    return await renderSingleItem(itemId, variant, bodyType, selections, singleLayer);
  }

  const config = ANIMATION_CONFIGS[animationName];
  if (!config) {
    console.error("Unknown animation:", animationName);
    return null;
  }

  const { row, num } = config;
  const animYPos = 0;
  const animHeight = num * FRAME_SIZE;

  // Create a new canvas for this animation
  const animCanvas = document.createElement("canvas");
  animCanvas.width = SHEET_WIDTH;
  animCanvas.height = animHeight;
  const animCtx = get2DContext(animCanvas);

  // Build list of sprites to draw for this item & animation
  const spritesToDraw = [];

  for (let layerNum = 1; layerNum < 10; layerNum++) {
    if (singleLayer !== null && layerNum !== singleLayer) continue;
    const layerKey = `layer_${layerNum}`;
    if (!meta.layers?.[layerKey]) break;

    const zPos = getZPos(itemId, layerNum);

    // Check animation support
    if (animationName === "combat_idle") {
      if (!meta.animations.includes("combat")) continue;
    } else if (animationName === "backslash") {
      if (
        !meta.animations.includes("1h_slash") &&
        !meta.animations.includes("1h_backslash")
      )
        continue;
    } else if (animationName === "halfslash") {
      if (!meta.animations.includes("1h_halfslash")) continue;
    } else {
      if (!meta.animations.includes(animationName)) continue;
    }

    const spritePath = getSpritePath(
      itemId,
      variant,
      bodyType,
      animationName,
      layerNum,
      selections,
      meta
    );

    spritesToDraw.push({
      spritePath,
      zPos,
      layerNum,
    });
  }

  // Sort by zPos
  spritesToDraw.sort((a, b) => a.zPos - b.zPos);

  // Load all images in parallel
  const loadedImages = await loadImagesInParallel(spritesToDraw);

  // Draw images in order
  for (const { item: sprite, img, success } of loadedImages) {
    if (success && img) {
      // Draw at y=0 since this canvas is only for this animation
      animCtx.drawImage(
        img,
        0,
        animYPos,
        SHEET_WIDTH,
        animHeight,
        0,
        0,
        SHEET_WIDTH,
        animHeight
      );
    }
  }

  return animCanvas;
}

