import TinyGesture from 'https://cdn.jsdelivr.net/npm/tinygesture@3.0.0/+esm';

export default class PinchToZoom {
    initialZoom = 1;
    currentZoom = 1;
    element = null;
    gesture = null;
    onZoom = null;

    constructor(element, onZoom, initialZoom = 1) {
        this.element = element;
        this.onZoom = onZoom;
        this.initialZoom = initialZoom || 1;
        this.currentZoom = this.initialZoom;

        this.init();
    }

    init() {
        this.gesture = new TinyGesture(this.element, { mouseSupport: false });

        this.gesture.on('pinch', (event) => {
            const scale = this.gesture.scale;
            this.currentZoom = this.initialZoom * scale;
            this.onZoom(this.currentZoom);
        });

        this.gesture.on('pinchend', (event) => {
            this.initialZoom = this.currentZoom;
        });
    }
}

// Scrollable container with drag-to-scroll support
export const ScrollableContainer = {
	oninit: function(vnode) {
		vnode.state.isDragging = false;
		vnode.state.startX = 0;
		vnode.state.startY = 0;
		vnode.state.scrollLeft = 0;
		vnode.state.scrollTop = 0;
	},
	oncreate: function(vnode) {
		const container = vnode.dom;

		// Mouse down - start dragging
		container.addEventListener('mousedown', (e) => {
			vnode.state.isDragging = true;
			vnode.state.startX = e.pageX - container.offsetLeft;
			vnode.state.startY = e.pageY - container.offsetTop;
			vnode.state.scrollLeft = container.scrollLeft;
			vnode.state.scrollTop = container.scrollTop;
			container.style.cursor = 'grabbing';
		});

		// Mouse leave/up - stop dragging
		const stopDragging = () => {
			vnode.state.isDragging = false;
			container.style.cursor = 'grab';
		};

		container.addEventListener('mouseleave', stopDragging);
		container.addEventListener('mouseup', stopDragging);

		// Mouse move - drag scroll
		container.addEventListener('mousemove', (e) => {
			if (!vnode.state.isDragging) return;
			e.preventDefault();
			const x = e.pageX - container.offsetLeft;
			const y = e.pageY - container.offsetTop;
			const walkX = (x - vnode.state.startX) * 1.5; // Scroll speed multiplier
			const walkY = (y - vnode.state.startY) * 1.5;
			container.scrollLeft = vnode.state.scrollLeft - walkX;
			container.scrollTop = vnode.state.scrollTop - walkY;
		});
	},
	view: function(vnode) {
		const {
			classes = ""
		} = vnode.attrs;

		return m(`div.scrollable-container.mt-3`, { class: classes }, vnode.children);
	}
};

// Current selections component
import { state } from '../../state/state.js';
import { isItemLicenseCompatible, isItemAnimationCompatible } from '../../state/filters.js';

export const CurrentSelections = {
	view: function() {
		const selectionCount = Object.keys(state.selections).length;

		if (selectionCount === 0) {
			return m("div", [
				m("h3.title.is-5", "Current Selections"),
				m("p.has-text-grey", "No items selected yet")
			]);
		}

		return m("div", [
			m("h3.title.is-5", "Current Selections"),
			m("div.tags",
				Object.entries(state.selections).map(([selectionKey, selection]) => {
					const isLicenseCompatible = isItemLicenseCompatible(selection.itemId);
					const isAnimCompatible = isItemAnimationCompatible(selection.itemId);
					const isCompatible = isLicenseCompatible && isAnimCompatible;
					const meta = window.itemMetadata?.[selection.itemId];

					// Get all licenses for this item
					const allLicenses = new Set();
					if (meta?.credits) {
						meta.credits.forEach(credit => {
							if (credit.licenses) {
								credit.licenses.forEach(lic => allLicenses.add(lic.trim()));
							}
						});
					}
					const licensesText = allLicenses.size > 0 ?
						`Licenses: ${Array.from(allLicenses).join(', ')}` :
						'No license info';

					// Get supported animations for this item
					const supportedAnims = meta?.animations || [];
					const animsText = supportedAnims.length > 0 ?
						`Animations: ${supportedAnims.join(', ')}` :
						'No animation info';

					// Build tooltip text
					let tooltipText = '';
					if (!isCompatible) {
						const issues = [];
						if (!isLicenseCompatible) issues.push('licenses');
						if (!isAnimCompatible) issues.push('animations');
						tooltipText = `⚠️ Incompatible with selected ${issues.join(' and ')}\n`;
					}
					tooltipText += `${licensesText}\n${animsText}`;

					return m("span.tag.is-medium", {
						key: selectionKey,
						class: isCompatible ? "is-info" : "is-warning",
						title: tooltipText
					}, [
						m("span", selection.name),
						!isCompatible ? m("span.ml-1", "⚠️") : null,
						m("button.delete.is-small", {
							onclick: () => {
								delete state.selections[selectionKey];

							}
						})
					]);
				})
			)
		]);
	}
};

