			m("div.mb-3", [
				m("label.checkbox", {
					title: "When enabled, changing body color will automatically update all compatible items (heads, ears, noses, etc.) to the same color variant"
				}, [
					m("input[type=checkbox]", {
						id: "match-body-color-checkbox",
						"aria-describedby": "match-body-color-label",
						checked: state.matchBodyColorEnabled,
						onchange: (e) => {
							state.matchBodyColorEnabled = e.target.checked;
							// If enabling the checkbox, immediately apply match body color
							if (e.target.checked) {
								// Use body-body as the source if available
								const bodySelectionGroup = getSelectionGroup('body-body');
								const bodySelection = state.selections[bodySelectionGroup];
								if (bodySelection?.variant) {
									applyMatchBodyColor(bodySelection.variant);
								}
							}
						}
					}),
					" Match body color"
				]),
				m("p.is-size-7.has-text-grey.mt-1.ml-4", {
					id: "match-body-color-label"
				}, "Auto-update heads, ears, and other items when body color changes")
			]),
			m("div", [
				// Body Type as first tree item
				m(BodyTypeSelector),
				// Rest of the category tree
				Object.entries(window.categoryTree.children || {}).map(([categoryName, categoryNode]) =>
					m(TreeNode, { key: categoryName, name: categoryName, node: categoryNode })
				)
			])
		]);
	}
};

// Item with variants component
import { state, getSelectionGroup, applyMatchBodyColor } from '../../state/state.js';
import { getLayersToLoad } from '../../state/meta.js';
import { variantToFilename, capitalize } from '../../utils/helpers.js';

const classNames = window.classNames;

export const ItemWithVariants = {
	view: function(vnode) {
		const { itemId, meta, isSearchMatch, isCompatible, tooltipText } = vnode.attrs;
		const compactDisplay = state.compactDisplay;
		const displayName = meta.name;
		const rootViewNode = vnode;
		let nodePath = itemId;
		if (displayName === 'Body Color') {
			nodePath = 'body-body';
		}
		const isExpanded = state.expandedNodes[nodePath] || false;
		const layers = getLayersToLoad(meta, state.bodyType, state.selections);

		return m("div", {
			class: classNames({
				"search-result": isSearchMatch,
				"has-text-grey": !isCompatible,
			}),
			oninit: () => {
				rootViewNode.state.isLoading = meta.variants.length > 0;
				rootViewNode.state.imagesToLoad = meta.variants.length * layers.length;
				rootViewNode.state.imagesLoaded = 0;
			},
			onupdate: () => {
				if (isExpanded && rootViewNode.state.isLoading) {
					if (rootViewNode.state.imagesLoaded >= rootViewNode.state.imagesToLoad) {
						rootViewNode.state.isLoading = false;
					}
				}
			}
		}, [
			m("div.tree-label", {
				title: tooltipText,
				onclick: () => {
					state.expandedNodes[nodePath] = !isExpanded;
					if (state.expandedNodes[nodePath]) {
						rootViewNode.state.isLoading = meta.variants.length > 0;
						rootViewNode.state.imagesToLoad = meta.variants.length * layers.length;
						rootViewNode.state.imagesLoaded = 0;
					}
				}
			}, [
				m("span.tree-arrow", { class: isExpanded ? 'expanded' : 'collapsed' }),
				m("span", displayName),
				!isCompatible ? m("span.ml-1", "⚠️") : null
			]),
			isExpanded ? m("div", [
				m("div", { class: rootViewNode.state.isLoading ? "loading" : "" }),
				m("div.variants-container.ml-5.is-flex.is-flex-wrap-wrap",
					meta.variants.map(variant => {
					const selectionGroup = getSelectionGroup(itemId);
					const isSelected = state.selections[selectionGroup]?.itemId === itemId &&
						state.selections[selectionGroup]?.variant === variant;
					const variantDisplayName = variant.replaceAll("_", " ");

					// Get preview metadata from item metadata
					const previewRow = meta.preview_row ?? 2;
					const previewCol = meta.preview_column ?? 0;
					const previewXOffset = meta.preview_x_offset ?? 0;
					const previewYOffset = meta.preview_y_offset ?? 0;

					// Get sprite path for preview image from first layer
					const layer1 = meta.layers?.layer_1;
					const basePath = layer1?.[state.bodyType];

					// Check if this item uses a custom animation
					const hasCustomAnimation = layer1?.custom_animation;
					const layer1CustomAnimation = hasCustomAnimation ? layer1.custom_animation : null;

					let previewSrc = null;
					if (basePath) {
						if (hasCustomAnimation) {
							// Custom animations don't have animation subfolders
							previewSrc = `spritesheets/${basePath}${variantToFilename(variant)}.png`;
						} else {
							// Standard animations have animation subfolders (walk, slash, etc.)
							const defaultAnim = meta.animations.includes('walk') ? 'walk' : meta.animations[0];
							previewSrc = `spritesheets/${basePath}${defaultAnim}/${variantToFilename(variant)}.png`;
						}
					}

					// Calculate object position for cropping
					// Negative position shifts the image left/up to show that part in the viewport
					// Positive offset values shift the viewport right/down (to see more left/top of sprite)
					// Negative offset values shift the viewport left/up (to see more right/bottom of sprite)
					const objectPosX = -(previewCol * 64 - previewXOffset);
					const objectPosY = -(previewRow * 64 - previewYOffset);

					return m("div.variant-item.is-flex.is-flex-direction-column.is-align-items-center.is-clickable", {
						key: variant,
						class: classNames({
							"has-background-link-light has-text-weight-bold has-text-link": isSelected,
							"is-not-compatible": !isCompatible,
						}),
						title: tooltipText,
						onmouseover: (e) => {
							if (!isCompatible) return;
							const div = e.currentTarget;
							if (!isSelected) div.classList.add('has-background-white-ter');
						},
						onmouseout: (e) => {
							if (!isCompatible) return;
							const div = e.currentTarget;

							if (!isSelected) div.classList.remove('has-background-white-ter');
						},
						onclick: () => {
							if (!isCompatible) return; // Prevent selecting incompatible
							const selectionGroup = getSelectionGroup(itemId);

							if (isSelected) {
								delete state.selections[selectionGroup];
							} else {
								state.selections[selectionGroup] = {
									itemId: itemId,
									variant: variant,
									name: `${displayName} (${variantDisplayName})`
								};

								// If this item has matchBodyColor enabled, apply to all other body-colored items
								if (meta.matchBodyColor) {
									applyMatchBodyColor(variant);
								}
							}
						}
					}, [
						m("span.variant-display-name.has-text-centered.is-size-7",
							capitalize(variantDisplayName)),
						m("canvas.variant-canvas.box.p-0", {
							width: compactDisplay ? 32 : 64,
							height: compactDisplay ? 32 : 64,
							class: (compactDisplay ? " compact-display" : ""),
							style: (isSelected ? " hsl(217, 71%, 53%)" : " hsl(0, 0%, 86%)"),
							oncreate: (canvasVnode) => {
								const canvas = canvasVnode.dom;
								const ctx = canvas.getContext('2d', { willReadFrequently: true });

								// Get Layers to Load for Variant
								const layersToLoad = getLayersToLoad(meta, state.bodyType, state.selections, variant);

								// Load and draw all layers
								Promise.all(layersToLoad.map(layer => {
									return new Promise((resolve) => {
										const img = new Image();
										img.onload = () => resolve({ img, layer });
										img.onerror = () => resolve({ img: null, layer });
										img.src = layer.path;
									});
								})).then(loadedLayers => {
									canvas.loadedLayers = loadedLayers;
									// Draw each layer in zPos order
									// Use universalFrameSize (64) for all calculations, matching master branch
									const universalFrameSize = 64;
									for (const { img, layer } of loadedLayers) {
										if (img) {
											const size = compactDisplay ? 32 : 64;
											// Master branch uses: previewColumn * universalFrameSize + previewXOffset
											const srcX = previewCol * universalFrameSize + previewXOffset;
											const srcY = previewRow * universalFrameSize + previewYOffset;
											ctx.drawImage(
												img,
												srcX, srcY, universalFrameSize, universalFrameSize,
												0, 0, size, size
											);
										}
									}
									rootViewNode.state.imagesLoaded += loadedLayers.length;
									m.redraw();
								});
							},
							onupdate: (canvasVnode) => {
								const canvas = canvasVnode.dom;
								const ctx = canvas.getContext('2d', { willReadFrequently: true });

								// Process Layers Loaded for Variant
								if (canvas.loadedLayers) {
									// Draw each layer in zPos order
									// Use universalFrameSize (64) for all calculations, matching master branch
									const universalFrameSize = 64;
									for (const { img, layer } of canvas.loadedLayers) {
										if (img) {
											const size = compactDisplay ? 32 : 64;
											// Master branch uses: previewColumn * universalFrameSize + previewXOffset
											const srcX = previewCol * universalFrameSize + previewXOffset;
											const srcY = previewRow * universalFrameSize + previewYOffset;
											ctx.drawImage(
												img,
												srcX, srcY, universalFrameSize, universalFrameSize,
												0, 0, size, size
											);
										}
									}
								}
							}
						})
					]);
				})
				)
			]) : null
		]);
	}
};

// Recursive tree node component
import { state, getSelectionGroup } from '../../state/state.js';
import {
  isItemLicenseCompatible,
  isItemAnimationCompatible,
  isNodeAnimationCompatible
} from '../../state/filters.js';
import { capitalize, matchesSearch, nodeHasMatches } from '../../utils/helpers.js';
import { ItemWithVariants } from './ItemWithVariants.js';

export const TreeNode = {
	view: function(vnode) {
		const { name, node, pathPrefix = "", label } = vnode.attrs;
		const nodePath = pathPrefix ? `${pathPrefix}-${name}` : name;
		const searchQuery = state.searchQuery;
		const hasSearchMatches = nodeHasMatches(node, searchQuery);
		const isNodeAnimCompatible = isNodeAnimationCompatible(node);

		// Filter: Only show items compatible with current body type
		if (node.required && node.required.length > 0 && !node.required.includes(state.bodyType)) return false;

		// Hide this node if search is active and there are no matches
		if (searchQuery && searchQuery.length >= 2 && !hasSearchMatches) {
			return null;
		}

		// Get supported animations for this item
		const supportedAnims = node.animations || [];
		const animsText = supportedAnims.length > 0 ?
			`Animations: ${supportedAnims.join(', ')}` :
			null;

		// Build tooltip text
		let tooltipText = '';
		if (!isNodeAnimCompatible) {
			tooltipText = `⚠️ Incompatible with selected animations\n`;
		}
		tooltipText += `${animsText}`;

		// Auto-expand if search is active and has matches
		const isExpanded = (searchQuery && searchQuery.length >= 2 && hasSearchMatches) || state.expandedNodes[nodePath] || false;
		const displayName = node.label ?? capitalize(name);

		return m("div",
			m("div.tree-label", {
				class: `${!isNodeAnimCompatible ? "has-text-grey" : ""}`,
				title: tooltipText,
				onclick: () => {
					if (!isNodeAnimCompatible) return; // Prevent selecting incompatible
					state.expandedNodes[nodePath] = !isExpanded;
				}
			}, [
				m("span.tree-arrow", { class: isExpanded ? 'expanded' : 'collapsed' }),
				m("span", displayName),
				!isNodeAnimCompatible ? m("span.ml-1", "⚠️") : null
			]),
			isExpanded ? m("div.ml-4", [
				// Render child categories
				Object.entries(node.children || {}).map(([childName, childNode]) =>
					m(TreeNode, { key: childName, name: childName, node: childNode, pathPrefix: nodePath })
				),
				// Render items in this category
				(node.items || [])
					.filter(itemId => {
						const meta = window.itemMetadata[itemId];
						// Filter: Only show items compatible with current body type
						if (!meta || !meta.required.includes(state.bodyType)) return false;
						if (!isItemAnimationCompatible(itemId) || !isNodeAnimCompatible) return false;

						// Filter: Only show items matching search query
						if (searchQuery && searchQuery.length >= 2 && !matchesSearch(meta.name, searchQuery)) {
							return false;
						}

						return true;
					})
					.map(itemId => {
						const meta = window.itemMetadata[itemId];
						const displayName = meta.name;
						const hasVariants = meta.variants && meta.variants.length > 0;
						const isSearchMatch = searchQuery && searchQuery.length >= 2 && matchesSearch(meta.name, searchQuery);

						const isLicenseCompatibleFlag = isItemLicenseCompatible(itemId);
						const isAnimCompatibleFlag = isItemAnimationCompatible(itemId) && isNodeAnimCompatible;
						const isCompatible = isLicenseCompatibleFlag && isAnimCompatibleFlag;

						// Build tooltip text
						const allLicenses = new Set();
						if (meta?.credits) {
							meta.credits.forEach(credit => {
								if (credit.licenses) {
									credit.licenses.forEach(lic => allLicenses.add(lic.trim()));
								}
							});
						}
						const licensesText = allLicenses.size > 0 ?
							`Licenses: ${Array.from(allLicenses).join(', ')}` :
							'No license info';

						const supportedAnims = meta?.animations || [];
						const animsText = supportedAnims.length > 0 ?
							`Animations: ${supportedAnims.join(', ')}` :
							'No animation info';

						let tooltipText = '';
						if (!isCompatible) {
							const issues = [];
							if (!isLicenseCompatibleFlag) issues.push('licenses');
							if (!isAnimCompatibleFlag) issues.push('animations');
							tooltipText = `⚠️ Incompatible with selected ${issues.join(' and ')}\n`;
						}
						tooltipText += `${licensesText}\n${animsText}`;

						if (!hasVariants) {
							// Simple item with no variants
							const selectionGroup = getSelectionGroup(itemId);
							const isSelected = state.selections[selectionGroup]?.itemId === itemId;
							return m("div.tree-node", {
								key: itemId,
								class: `${isSearchMatch ? "search-result" : ""} ${!isCompatible ? "has-text-grey" : ""}`,
								style: (isSelected ? " font-weight: bold; color: #3273dc;" : ""),
								title: tooltipText,
								onclick: () => {
									if (!isCompatible) return; // Prevent selecting incompatible
									if (isSelected) {
										delete state.selections[selectionGroup];
									} else {
										state.selections[selectionGroup] = { itemId, name: displayName };
									}
								}
							}, [
								displayName,
								!isCompatible ? m("span.ml-1", "⚠️") : null
							]);
						}

						// Item with variants - create a sub-component
						return m(ItemWithVariants, { key: itemId, itemId, meta, isSearchMatch, isCompatible, tooltipText });
					})
			]) : null
		);
	}
};

