body {
  height: 100dvh;
  font-family: monospace;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: flex-start;
}

h1 {
  margin: 10px 0px;
}

h2 {
  margin: 10px 0px;
}

h3 {
  margin: 4px 0px 0px 0px;
}

p {
  margin: 10px 0px;
}

.sticky {
  position: sticky;
  top: 0;
  opacity: 1;
  background-color: white;
  z-index: 100;
}

#header-left {
  width: calc(100% - 30px);
  padding: 10px;
  box-sizing: border-box;
  min-height: 75px;
}

#columns-container {
  width: 100%;
  flex: 1;
  margin-top: 0;
  overflow-y: auto;
}

#chooser-column {
  padding: 1rem;
  overflow-y: auto;
  scroll-behavior: smooth;
}

#preview-column {
  padding: 1rem;
  overflow-y: auto;
}

#download-buttons {
  gap: 0.5rem;
}

#credits-section > .collapsible-content > .content {
  max-height: 300px;
  overflow-y: auto;
}

#animations-preview, #spritesheet-preview {
  touch-action: pan-x pan-y;
}

/* Prevent canvas antialiasing/blurring */
canvas {
  image-rendering: pixelated;
  image-rendering: -moz-crisp-edges;
  image-rendering: crisp-edges;
}

#previewAnimations, #spritesheet-preview {
  image-rendering: pixelated;
  image-rendering: -moz-crisp-edges;
  image-rendering: crisp-edges;
}

.spritesheet-preview {
  position: relative;
}

.spritesheet-preview .loading {
  position: absolute;
  top: 1rem;
  left: 1rem;
}

.scrollable-container {
  overflow: auto;
  max-width: 100%;
  max-height: 70vh;
  cursor: grab;
  user-select: none;
}

.variants-container {
  gap: 0.5rem;
}

.variants-container:has(.compact-display) {
  max-height: 300px;
  overflow: auto;
}

.variant-item {
  gap: 0.25rem;
  border-radius: 4px;
  transition: background-color 0.15s;
  min-width: 80px;
  max-width: 120px;
  padding: 0.5rem 0.5rem 0.25rem 0.5rem;
}

.variant-item:has(.compact-display) {
  padding: 0.125rem;
  gap: 0.125rem;
}

.variant-display-name {
