import { customAnimationBase, customAnimations } from "../custom-animations.js";
import { LICENSE_CONFIG, ANIMATIONS } from "./constants.js";
import { state } from "./state.js";

// Dependency injection for testability
const deps = {
  animations: ANIMATIONS,
  licenseConfig: LICENSE_CONFIG,
  state,
  customAnimations,
  customAnimationBase
};

export function getLicenseConfig() {
  return deps.licenseConfig;
}

export function setLicenseConfig(config) {
  deps.licenseConfig = config;
}

export function setAnimations(anims) {
  deps.animations = anims;
}

export function getAnimations() {
  return deps.animations;
}

export function getState() {
  return deps.state;
}

export function updateState(updates) {
  Object.assign(deps.state, updates);
}

export function resetState() {
  deps.state.bodyType = "male";
  deps.state.selections = {};
  deps.state.enabledLicenses = {};
  deps.state.enabledAnimations = {};
}

export function getCustomAnimationBase() {
  return deps.customAnimationBase(...arguments);
}

export function setCustomAnimationBase(func) {
  deps.customAnimationBase = func;
}

export function getCustomAnimations() {
  return deps.customAnimations;
}

export function setCustomAnimations(anims) {
  deps.customAnimations = anims;
}

export function getEnabledLicenses() {
  return deps.state.enabledLicenses;
}

export function setEnabledLicenses(enabledLicenses) {
  updateState({
    enabledLicenses:
      Object.fromEntries(
        enabledLicenses.map(key => [key, true])
      )
  });
}

export function getEnabledAnimations() {
  return deps.state.enabledAnimations;
}

export function setEnabledAnimations(enabledAnimations) {
  updateState({
    enabledAnimations:
      Object.fromEntries(
        enabledAnimations.map(key => [key, true])
      )
  });
}

// Helper function to get all allowed license strings (expanded from categories)
export function getAllowedLicenses() {
	const allowed = [];
	for (const license of getLicenseConfig()) {
		if (getEnabledLicenses()[license.key]) {
			allowed.push(...license.versions);
		}
	}
	return allowed;
}

// Helper function to check if an item is compatible with selected licenses
export function isItemLicenseCompatible(itemId) {
	const meta = window.itemMetadata?.[itemId];
	if (!meta || !meta.credits || meta.credits.length === 0) return true; // No license info = assume compatible

	const allowedLicenses = getAllowedLicenses();
	if (allowedLicenses.length === 0) return false; // No licenses selected = nothing compatible

	// Create normalized Set for fast lookup
	const allowedSet = new Set(allowedLicenses.map((l) => l.trim()));

	// Check if item has at least one credit with a compatible license
	for (const credit of meta.credits) {
		if (credit.licenses && credit.licenses.length > 0) {
			const hasCompatibleLicense = credit.licenses.some((license) =>
				allowedSet.has(license.trim()),
			);
			if (hasCompatibleLicense) return true;
		}
	}

	return false;
}

// Helper function to check if an item is compatible with selected animations
export function isItemAnimationCompatible(itemId) {
	const meta = window.itemMetadata?.[itemId];
  return isNodeAnimationCompatible(meta);
}

// Helper function to check if a node path is compatible with selected animations
export function isNodeAnimationCompatible(node) {
	// Get list of enabled animations
	const enabledAnims = getAnimations().filter(
		(anim) => getEnabledAnimations()[anim.value],
	).map((anim) => anim.value);

	// If no animations are selected, filter is disabled - show all items
	if (enabledAnims.length === 0) return true;

	const meta = node;
	if (!meta || !meta.animations || meta.animations.length === 0) return true; // No animation info = assume compatible

	// Check if item supports at least one enabled animation
	for (const itemAnim of meta.animations) {
		if (enabledAnims.includes(itemAnim)) return true;

    // check if enabledAnims includes base version of itemAnim
    const customAnim = getCustomAnimations()[itemAnim];
    if (!customAnim) continue;
    const baseItemAnim = getCustomAnimationBase(customAnim);
    if (baseItemAnim && enabledAnims.includes(baseItemAnim)) return true;
	}

	return false;
}

import { state, selectDefaults } from "./state.js";

// Dependency injection for testability
export function getState() {
  return state;
}

export function updateState(updates) {
  Object.assign(state, updates);
}

export function resetState() {
  state.bodyType = "male";
  state.selections = {};
}

// window.location.hash is immutable in tests, this is so we can use a stub to manage it
let _hash = "";
let _setHashCalledTimes = 0;

export function getHash() {
  if (window.isTesting) return "#" + _hash;
  return window.location.hash;
}

export function setHash(hash) {
  if (window.isTesting) {
    _hash = hash[0] === "#" ? hash.substring(1) : hash;
    _setHashCalledTimes++;
    return;
  }
  window.location.hash = hash;
}

export function resetHashCalledTimes() {
  _setHashCalledTimes = 0;
}

export function getSetHashCalledTimes() {
  return _setHashCalledTimes;
}

// URL hash parameter management
export function getHashParams() {
  let hash = getHash().substring(1); // Remove '#'

  // Handle case where hash starts with '?' (some old URLs might have this)
  if (hash.startsWith("?")) {
    hash = hash.substring(1);
  }

  if (!hash) return {};

  return getHashParamsFromString(hash);
}

export function getHashParamsFromString(hashString) {
  const params = {};
  hashString.split("&").forEach((pair) => {
    const [key, value] = pair.split("=");
    if (key && value) {
      // Remove leading '?' from key if present
      const cleanKey = key.startsWith("?") ? key.substring(1) : key;
      params[decodeURIComponent(cleanKey)] = decodeURIComponent(value);
    }
  });
  return params;
}

export function createHashStringFromParams(params) {
  return Object.entries(params)
    .map(
      ([key, value]) =>
        `${encodeURIComponent(key)}=${encodeURIComponent(value)}`,
    )
    .join("&");
}

export function setHashParams(params) {
  const hash = createHashStringFromParams(params);
  setHash(hash);
}

export function getHashParamsforSelections(selections) {
  const params = {};

  // Add body type (using 'sex' for backwards compatibility with old URLs)
  params.sex = state.bodyType;

  // Add selections - use old format: type_name=Name_variant
  // Format: "body=Body_color_light", "shoes=Sara_sara"
  for (const [typeName, selection] of Object.entries(selections)) {
    const meta = window.itemMetadata?.[selection.itemId];
    if (!meta || !meta.type_name) {
      // Check if an alias is overriding this entry (e.g., "sash=Waistband_rose" instead of "waistband=Waistband_rose")
      const name = selection.name.split(" (")[0]; // Get base name without variant (e.g., "Waistband" from "Waistband (rose)")
      const nameAndVariant = name.replaceAll(" ", "_") + (selection.variant ? `_${selection.variant}` : "");
      const aliasMeta = window.aliasMetadata?.[typeName]?.[nameAndVariant];
      if (!aliasMeta || !aliasMeta.typeName) continue;

      params[aliasMeta.typeName] = `${aliasMeta.name}_${aliasMeta.variant}`;
    } else {
      // Use type_name as key (selection group)
      const key = meta.type_name;

      // Build name part for URL: use full name with underscores
      // "Body color" -> "Body_color", "Sara Shoes" -> "Sara_Shoes", "Waistband" -> "Waistband"
      const namePart = meta.name.replaceAll(" ", "_");

      const variantPart = selection.variant ? `_${selection.variant}` : "";
      const value = namePart + variantPart;

      params[key] = value;
    }
  }

  return params;
}

export function syncSelectionsToHash() {
  const params = getHashParamsforSelections(state.selections);
  setHashParams(params);
}

export function loadSelectionsFromHash(hashString = null) {
  const params = hashString
    ? getHashParamsFromString(hashString)
    : getHashParams();

  // Build new selections object without mutating state yet
  const newSelections = {};

  // Load selections
  // Old format: type_name=Name_variant (e.g., "body=Body_color_light", "sash=Waistband_rose")
  for (let [typeName, nameAndVariant] of Object.entries(params)) {
    // Handle special parameters
    if (typeName === "bodyType" || typeName === "sex") {
      state.bodyType = nameAndVariant;
      continue;
    }

    // Check if this is an aliased selection and resolve it to the canonical type, name, and variant
    const aliasMeta = window.aliasMetadata?.[typeName]?.[nameAndVariant];
    if (aliasMeta) {
      typeName = aliasMeta.typeName;
      nameAndVariant = `${aliasMeta.name}_${aliasMeta.variant}`;
    }

    // Skip "none" selections
    if (nameAndVariant === "none") continue;

    // Parse the Name_variant format by trying different split positions
    // Try from left to right to find a valid name+variant combination
    // e.g., "Tiara_tiara_silver" -> try "Tiara" + "tiara_silver" ✓
    // e.g., "Human_female_light" -> try "Human_female" + "light" ✓

    let foundItemId = null;
    let matchedVariant = "";

    // Split on underscores and try different combinations
    const parts = nameAndVariant.split("_");

    // Try each possible split point (from left to right)
    for (let i = 1; i <= parts.length; i++) {
      const nameToMatch = parts.slice(0, i).join("_");
      const variantToMatch = parts.slice(i).join("_");

      // Search for item with this name and variant
      for (const [itemId, meta] of Object.entries(window.itemMetadata || {})) {
        if (meta.type_name !== typeName) continue;

        const metaNameNormalized = meta.name.replaceAll(" ", "_");

        // Check if name matches and variant exists (or no variant required)
        if (metaNameNormalized.toLowerCase() === nameToMatch.toLowerCase()) {
          if (meta.variants?.length > 0) {
            for (const variant of meta.variants) {
              if (variant.toLowerCase() === variantToMatch.toLowerCase()) {
                foundItemId = itemId;
                matchedVariant = variant;
                break;
              }
            }
          } else if (variantToMatch === "") {
            // No variants for this item, so we can match just on name
            foundItemId = itemId;
            matchedVariant = "";
            break;
          }
        }

        if (foundItemId) break;
      }

      if (foundItemId) break;
    }

    if (!foundItemId) {
      if (window.DEBUG) {
        console.warn(
          `No item found with type_name "${typeName}" and nameAndVariant "${nameAndVariant}"`,
        );
      }
      continue;
    }

    const meta = window.itemMetadata[foundItemId];

    // Use type_name as selection group
    const selectionGroup = typeName;
    newSelections[selectionGroup] = {
      itemId: foundItemId,
      variant: matchedVariant || meta.variants?.[0] || "",
      name: meta.name + (matchedVariant ? ` (${matchedVariant})` : ""),
    };
  }

  // Now update state once with complete new selections
  state.selections = newSelections;

  // Load body type
  if (params.bodyType) {
    state.bodyType = params.bodyType;
  }

  syncSelectionsToHash(); // Ensure hash is in sync with loaded selections (handles any normalization)
}

// Initialize hash change listener
export function initHashChangeListener(listener) {
  // Store the current hash to detect external changes
  let lastKnownHash = getHash();

  if (listener) {
    window.addEventListener("hashchange", listener);
    return;
  }

  // Listen for browser back/forward navigation
  window.addEventListener("hashchange", async function () {
    const currentHash = getHash();

    // Check if this is an external change (browser navigation) vs our own update
    // Our afterStateChange() will update the hash, but we don't want to reload from it
    // We can detect external changes by checking if the hash is different from what we expect
    const expectedHash =
      "#" +
      Object.entries({
        bodyType: state.bodyType,
        ...Object.fromEntries(
          Object.values(state.selections).map((s) => [
            s.itemId,
            s.variant || "",
          ]),
        ),
      })
        .map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(v)}`)
        .join("&");

    // If the hash matches what we expect from current state, ignore (it's our own update)
    if (currentHash === expectedHash) {
      lastKnownHash = currentHash;
      return;
    }

    // Load from hash (updates state once)
    loadSelectionsFromHash();

    // If nothing loaded from hash, use defaults
    if (Object.keys(state.selections).length === 0) {
      await selectDefaults();
    }

    // Trigger redraw which calls App.onupdate (syncs hash and renders canvas)
    m.redraw();

    lastKnownHash = currentHash;
  });
}

import { createHashStringFromParams, getHashParamsforSelections, loadSelectionsFromHash } from "./hash.js";
import { getAllCredits } from "../utils/credits.js";
import { state } from "../state/state.js";

/**
 * Export current state as JSON string
 */
export function exportStateAsJSON(state, layers) {
	const hash = createHashStringFromParams(getHashParamsforSelections(state.selections));
	const url = `${window.location.origin}${window.location.pathname}#${hash}`;
	const exportedState = {
		version: 2,
		bodyType: state.bodyType,
		selections: state.selections,
		selectedAnimation: state.selectedAnimation,
		showTransparencyGrid: state.showTransparencyGrid,
		applyTransparencyMask: state.applyTransparencyMask,
		matchBodyColorEnabled: state.matchBodyColorEnabled,
		compactDisplay: state.compactDisplay,
		enabledLicenses: state.enabledLicenses,
		enabledAnimations: state.enabledAnimations,
		url,
		layers,
		credits: getAllCredits(state.selections, state.bodyType),
	};
	return JSON.stringify(exportedState, null, 2);
}

/**
 * Import state from JSON string
 */
export function importStateFromJSON(jsonString) {
	try {
		const importedState = JSON.parse(jsonString);
		if (!importedState.version || 
			(importedState.version === 1 && !importedState.url) ||
			(importedState.version === 2 && (!importedState.bodyType || !importedState.selections))) {
			throw new Error("Invalid JSON format");
		}
		if (importedState.version === 2) {
			const newState = {
				bodyType: importedState.bodyType,
				selections: importedState.selections,
				selectedAnimation: importedState.selectedAnimation ?? state.selectedAnimation,
				showTransparencyGrid: importedState.showTransparencyGrid ?? state.showTransparencyGrid,
				applyTransparencyMask: importedState.applyTransparencyMask ?? state.applyTransparencyMask,
				matchBodyColorEnabled: importedState.matchBodyColorEnabled ?? state.matchBodyColorEnabled,
				compactDisplay: importedState.compactDisplay ?? state.compactDisplay,
				enabledLicenses: importedState.enabledLicenses ?? state.enabledLicenses,
				enabledAnimations: importedState.enabledAnimations ?? state.enabledAnimations,
			};
			return newState;
		} else if (importedState.version === 1) {
			const url = new URL(importedState.url);
			const hash = url.hash.toString().substring(1);
			loadSelectionsFromHash(hash);
		} else {
			throw new Error("Unsupported version");
		}
	} catch (err) {
		console.error("Failed to parse JSON:", err);
		throw err;
	}
}

import { getZPos } from '../canvas/canvas-utils.js';
import { variantToFilename } from '../utils/helpers.js';
import { replaceInPath } from './path.js';

/**
 * Sort Layers by zPos
 * 
 * @param {string} itemId - The ID of the item to get layers for
 * @param {boolean} standardOnly - If true, only include standard animation layers
 * @returns {Array} Sorted array of layers with layerNum and zPos
 */
export function getSortedLayers(itemId, standardOnly = false) {
  const meta = window.itemMetadata[itemId];
  if (!meta) {
    console.error('Item metadata not found:', itemId);
    return null;
  }

  // Build list of layers for itemId
  const layersList = [];
  for (let layerNum = 1; layerNum < 10; layerNum++) {
    const layerKey = `layer_${layerNum}`;
    const layer = meta.layers?.[layerKey];
    if (!layer) break;
    if (standardOnly && layer.custom_animation) continue;

    const zPos = getZPos(itemId, layerNum);

    layersList.push({ layerNum, zPos });
  }

  // Sort by animation first, then by zPos
  layersList.sort((a, b) => {
    return a.zPos - b.zPos;
  });
  return layersList;
}

/**
 * Split Layers by Animation Type, Then Sort by zPos
 * 
 * @param {string} itemId - The ID of the item to get layers for
 * @param {boolean} customOnly - If true, only include custom animation layers
 * @returns {Object} Object with animation names as keys and sorted arrays of layers
 */
export function getSortedLayersByAnim(itemId, customOnly = false) {
  const meta = window.itemMetadata[itemId];
  if (!meta) {
    console.error('Item metadata not found:', itemId);
    return null;
  }

  // Build list of layers for itemId
  const animsList = {};
  for (let layerNum = 1; layerNum < 10; layerNum++) {
    const layerKey = `layer_${layerNum}`;
    const layer = meta.layers?.[layerKey];
    if (!layer) break;
    if (customOnly && !layer.custom_animation) continue;

    const animName = layer.custom_animation || 'standard';
    if (!animsList[animName]) {
      animsList[animName] = [];
    }

    const zPos = getZPos(itemId, layerNum);

    animsList[animName].push({ layerNum, zPos });
  }

  // Sort Each Animation's Layers By zPos
  for (const animName in animsList) {
    animsList[animName] = animsList[animName].sort((a, b) => {
      return a.zPos - b.zPos;
    }).map((layer, index) => {
      return { layerNum: layer.layerNum, animLayerNum: index + 1, zPos: layer.zPos };
    });
  }

  return animsList;
}

/**
 * Get Layers to Load for the given metadata and variant
 * @param {Object} meta - Metadata for the asset
 * @param {string} bodyType - The body type that is currently selected
 * @param {Object} selections - Currently selected assets
 * @param {string|null} variant - Variant name for the asset (optional)
 * @return {Array} Array of layers to load
 */
export function getLayersToLoad(meta, bodyType, selections, variant = null) {
  // Check if this item uses a custom animation
  const layer1 = meta.layers?.layer_1;
  const hasCustomAnimation = layer1?.custom_animation;
  const layer1CustomAnimation = hasCustomAnimation ? layer1.custom_animation : null;

  // Collect all layers for this item
  // Only include layers that match layer_1's custom animation (if any)
  const layersToLoad = [];
  for (let layerNum = 1; layerNum < 10; layerNum++) {
    const layer = meta.layers?.[`layer_${layerNum}`];
    if (!layer) break;

    let layerPath = layer[bodyType];
    if (!layerPath) continue;

    // Filter: only include layers with matching custom animation
    if (layer1CustomAnimation) {
      if (layer.custom_animation !== layer1CustomAnimation) {
        continue; // Skip layers with different custom animations
      }
    }

    // Replace template variables like ${head}
    if (layerPath.includes('${')) {
      layerPath = replaceInPath(layerPath, selections, meta);
    }

    const hasCustomAnim = layer.custom_animation;
    let imagePath;
    const variantFileName = variant !== null ? `${variantToFilename(variant)}` : '';
    if (hasCustomAnim) {
      imagePath = `spritesheets/${layerPath}${variantFileName}.png`;
    } else {
      const defaultAnim = meta.animations.includes('walk') ? 'walk' : meta.animations[0];
      imagePath = `spritesheets/${layerPath}${defaultAnim}${variantFileName ? `/${variantFileName}` : ''}.png`;
    }

    layersToLoad.push({
      zPos: layer.zPos ?? 100,
      path: imagePath
    });
  }
  return layersToLoad.sort((a, b) => a.zPos - b.zPos);
}

import { ANIMATIONS } from './constants.js';
import { getHashParamsforSelections } from './hash.js';
import { variantToFilename, es6DynamicTemplate } from '../utils/helpers.js';

/**
 * Build sprite path from item metadata for a specific animation
 */
export function getSpritePath(itemId, variant, bodyType, animName, layerNum = 1, selections = {}, meta = null) {
  if (!meta) {
    meta = window.itemMetadata[itemId];
  }
  if (!meta) return null;

  const layerKey = `layer_${layerNum}`;
  const layer = meta.layers?.[layerKey];
  if (!layer) return null;

  // Get the file path for this body type
  let basePath = layer[bodyType];
  if (!basePath) return null;

  // Replace template variables like ${head}
  if (basePath.includes('${')) {
	basePath = replaceInPath(basePath, selections, meta);
  }

  // If no variant specified, try to extract from itemId
  if (!variant) {
    const parts = itemId.split('_');
    variant = parts[parts.length - 1];
  }

  // Determine animation name to use in path
  const animation = ANIMATIONS.find(a => a.value === animName);
  if (animation?.folderName) {
	animName = animation.folderName;
  }

  // Build full path: spritesheets/ + basePath + animation/ + variant.png
  return `spritesheets/${basePath}${animName}/${variantToFilename(variant)}.png`;
}

// Replace template variables like ${head} in a path using current selections
export function replaceInPath(path, selections, meta) {
	if (path.includes("${")) {
		// get params from selections
		// TODO: this could be optimized to avoid recomputing every time
		// or to only do it when relevant selections change
		// or just use the selections directly instead of recomputing the hash params
		const hashParams = getHashParamsforSelections(selections || {});
		const replacements = Object.fromEntries(
			Object.entries(hashParams).map(([typeName, nameAndVariant]) => {
				const name = getNameWithoutVariant(typeName, nameAndVariant);
				const replacement = meta.replace_in_path[typeName]?.[name];
				if (window.DEBUG) {
					if (path.includes(`\${${typeName}}`) && !replacement) {
						console.log(`Warning: No replacement found for ${typeName}="${name}" in path template.`);
					}
				}
				return [typeName, replacement];
			}),
		);

		return es6DynamicTemplate(path, replacements);
	}

	return path;
}

const indexedMetadataCache = new Map();

for (const key of Object.keys(window.itemMetadata || {})) {
	const item = window.itemMetadata[key];
	const indexKey = item.type_name;
	if (indexedMetadataCache.has(indexKey)) {
		const existing = indexedMetadataCache.get(indexKey);
		existing.push(item);
	} else {
		indexedMetadataCache.set(indexKey, [item]);
	}
}

// Helper to extract name without variant from a nameAndVariant string
// This is way too complex because both names and variants can have underscores in them
// Perhaps we should change the naming convention to avoid this ambiguity
// e.g. use double underscore to separate name and variant in item ids
function getNameWithoutVariant(typeName, nameAndVariant) {
	let variant = '';
	const nameAndVariantPath = nameAndVariant.split('_');
	const l = nameAndVariantPath.length;
	const names = indexedMetadataCache.get(typeName) || [];
	const variants = names.flatMap(n => n.variants || []).map(v => v.toLowerCase());
	let j = l;
	let v = 0;
	while (--j > 0) {
		const part = nameAndVariantPath.slice(j, l).join('_');
		if (variants?.includes(part.toLowerCase())) {
			variant = part;
			v = j;
		}
	}
	const name = variant ? nameAndVariantPath.slice(0, v).join('_') : nameAndVariantPath.slice(0, l - 1).join('_');
	return name;
}

