      let lastUsedPath = null;

      for (const usedPath of usedPaths) {
        // Match if used path equals or starts with the credit file path
        // e.g., usedPath="eyes/human/adult/neutral" matches credit.file="eyes/human" or "eyes/human/adult"
        if (usedPath === creditFile || usedPath.startsWith(creditFile + "/")) {
          isUsed = true;
          lastUsedPath = usedPath;
          break;
        }
      }

      if (isUsed && !seenFiles.has(lastUsedPath)) {
        allCredits.push({ fileName: lastUsedPath, ...credit });
        seenFiles.add(lastUsedPath);
      }
    }
  }

  return allCredits;
}

/**
 * Helper function to convert credits to CSV format
 */
export function creditsToCsv(allCredits) {
  const header = "filename,notes,authors,licenses,urls";
  let csvBody = header + "\n";
  allCredits.forEach((credit) => {
    const authors = credit.authors.join(", ");
    const licenses = credit.licenses.join(", ");
    const urls = credit.urls.join(", ");
    const notes = credit.notes || "";
    csvBody += `"${credit.fileName}","${notes}","${authors}","${licenses}","${urls}"\n`;
  });
  return csvBody;
}

/**
 * Helper function to convert credits to TXT format
 */
export function creditsToTxt(allCredits) {
  let txt = "";
  allCredits.forEach((credit) => {
    txt += `${credit.fileName}\n`;
    if (credit.notes) {
      txt += `\t- Note: ${credit.notes}\n`;
    }
    txt += `\t- Licenses:\n\t\t- ${credit.licenses.join("\n\t\t- ")}\n`;
    txt += `\t- Authors:\n\t\t- ${credit.authors.join("\n\t\t- ")}\n`;
    txt += `\t- Links:\n\t\t- ${credit.urls.join("\n\t\t- ")}\n\n`;
  });
  return txt;
}

function addExtensionIfMissing(filename, extension) {
  if (filename.toLowerCase().endsWith(extension.toLowerCase())) {
    return filename;
  }
  return `${filename}.${extension}`;
}

/**
 * Helper function to get item filename with zPos prefix
 */
export function getItemFileName(itemId, variant, name, layerNum = 1, zOverride = null) {
	const meta = window.itemMetadata[itemId];
	if (!meta) return addExtensionIfMissing(name, "png");

	// Get zPos from specified layer
	const layer = meta.layers?.[`layer_${layerNum}`];
	if (!layer) throw new Error("Requested layer number " + layerNum + " not found for item: " + itemId);
	const zPos = zOverride || layer?.zPos || 100;
	const altName = `${itemId}_${variant ?? ''}`;

	// Format: "050 body_male_light" (zPos padded to 3 digits + space + name)
	const safeName = (name || altName).replace(/[^a-z0-9.]/gi, "_").toLowerCase();
	const fileName = `${String(zPos).padStart(3, "0")} ${safeName}`;
	return addExtensionIfMissing(fileName, "png");
}

// Pure utility functions with no state dependencies

/**
 * Simple ES6 template string replacement
 * e.g. es6DynamicTemplate("Hello ${name}", {name: "World"}) => "Hello World"
 * Note: does not support complex expressions, only simple variable replacement
 * @param {string} templateString - Template string with ${var} placeholders
 * @param {Object} templateVariables - Object with variable values
 * @returns {string} - Resulting string with variables replaced
 */
// copied from https://github.com/mikemaccana/dynamic-template/blob/046fee36aecc1f48cf3dc454d9d36bb0e96e0784/index.js
export const es6DynamicTemplate = (templateString, templateVariables) =>
	templateString.replace(/\${(.*?)}/g, (_, g) => templateVariables[g] ?? `\${${g}}`);

/**
 * Convert variant name to filename format (spaces to underscores)
 * @param {string} variant - Variant name (e.g., "light brown")
 * @returns {string} - Filename format (e.g., "light_brown")
 */
export function variantToFilename(variant) {
	return variant.replaceAll(' ', '_');
}

/**
 * Helper function to capitalize strings for display
 */
export function capitalize(str) {
	return str.charAt(0).toUpperCase() + str.slice(1);
}

/**
 * Helper function to check if item matches search query
 */
export function matchesSearch(text, query) {
	if (!query || query.length < 2) return true;
	return text.toLowerCase().includes(query.toLowerCase());
}

/**
 * Helper function to check if a node or its children contain search matches
 */
export function nodeHasMatches(node, query) {
	if (!query || query.length < 2) return true;

	// Check if any items in this node match
	if (node.items && node.items.some(itemId => {
		const meta = window.itemMetadata[itemId];
		return meta && matchesSearch(meta.name, query);
	})) {
		return true;
	}

	// Check if any child nodes have matches
	if (node.children) {
		return Object.values(node.children).some(childNode => nodeHasMatches(childNode, query));
	}

	return false;
}

