    });
  });

  describe('capitalize', () => {
    it('should capitalize the first letter of the string', () => {
      const str = 'hello';
      const result = capitalize(str);
      expect(result).to.equal('Hello');
    });

    it('should return the same string if the first letter is already capitalized', () => {
